```go
package main

import (
    "fmt"
    "log"
    "net/url"
)

type Backend struct {
    URL   *url.URL
    Alive bool
}

func NewBackend(rawURL string) (*Backend, error) {
    u, err := url.Parse(rawURL)
    if err != nil {
        return nil, err
    }
    return &Backend{URL: u, Alive: true}, nil
}

func main() {
    urls := []string{
        "http://localhost:8081",
        "http://localhost:8082",
        "http://localhost:8083",
    }
    for _, rawURL := range urls {
        b, err := NewBackend(rawURL)
        if err != nil {
            log.Fatal(err)
        }
        port := b.URL.Port()
        fmt.Printf("%s: host=%s scheme=%s\n", port, b.URL.Host, b.URL.Scheme)
    }
}
```

statement:
The following code has a bug. Identify it and fix it:

```go
func printHost(b *Backend) {
    fmt.Println(b.URL.Host)
}

func main() {
    var b *Backend
    printHost(b)
}
```

solution:
`b` is a nil pointer (`var b *Backend` gives the zero value, which is `nil`). Calling `printHost(b)` passes a nil `*Backend`. Inside `printHost`, accessing `b.URL` dereferences the nil pointer, causing a panic.

Fix: initialize `b` before passing it:

```go
func main() {
    b, err := NewBackend("http://localhost:8080")
    if err != nil {
        log.Fatal(err)
    }
    printHost(b)
}
```

Or add a nil guard inside `printHost`:

```go
func printHost(b *Backend) {
    if b == nil {
        fmt.Println("no backend")
        return
    }
    fmt.Println(b.URL.Host)
}
```
